from elasticsearch import Elasticsearch
from elasticsearch.exceptions import TransportError
import json
import re
from typing import Dict, Any, Optional

class SecureElasticsearchClient:
    def __init__(self, hosts: list, **kwargs):
        self.es = Elasticsearch(hosts=hosts, **kwargs)
        self.allowed_scripts = {
            'sum', 'avg', 'min', 'max', 'count',
            'math', 'date', 'string', 'boolean'
        }
        
    def validate_script(self, script_code: str) -> bool:
        """Validate script code against security policies"""
        if not isinstance(script_code, str):
            return False
            
        # Check for dangerous patterns
        dangerous_patterns = [
            r'(\b(import|exec|eval|compile|__import__|open|file|os|sys|subprocess)\b)',
            r'(\b(__.*__)\b)',
            r'(\b(delattr|setattr|globals|locals|vars)\b)',
            r'(\b(while|for|if|try|except|finally|with)\b.*\b(continue|break)\b)',
        ]
        
        for pattern in dangerous_patterns:
            if re.search(pattern, script_code, re.IGNORECASE):
                return False
                
        # Check for maximum length
        if len(script_code) > 10000:
            return False
            
        return True
        
    def execute_aggregation_script(self, index: str, script: str, 
                                 aggregation_type: str = 'terms') -> Dict[str, Any]:
        """Execute secure aggregation script"""
        if not self.validate_script(script):
            raise ValueError("Invalid script code")
            
        try:
            # Build aggregation query
            agg_query = {
                "aggs": {
                    "result": {
                        aggregation_type: {
                            "script": {
                                "source": script
                            }
                        }
                    }
                }
            }
            
            # Execute query
            response = self.es.search(
                index=index,
                body=agg_query,
                request_cache=False,
                timeout="30s"
            )
            
            return response
            
        except TransportError as e:
            raise Exception(f"ES Transport Error: {str(e)}")
        except Exception as e:
            raise Exception(f"Script execution failed: {str(e)}")
            
    def execute_dynamic_aggregation(self, index: str, 
                                  script_source: str,
                                  params: Optional[Dict] = None) -> Dict[str, Any]:
        """Execute dynamic aggregation with parameters"""
        if not self.validate_script(script_source):
            raise ValueError("Invalid script source")
            
        try:
            # Build aggregation with parameters
            agg_query = {
                "aggs": {
                    "result": {
                        "terms": {
                            "script": {
                                "source": script_source,
                                "params": params or {}
                            }
                        }
                    }
                }
            }
            
            response = self.es.search(
                index=index,
                body=agg_query,
                request_cache=False,
                timeout="30s"
            )
            
            return response
            
        except TransportError as e:
            raise Exception(f"ES Transport Error: {str(e)}")
        except Exception as e:
            raise Exception(f"Dynamic aggregation failed: {str(e)}")

